import { chromium } from "playwright";
const OUT = "/tmp/claude-1000/-home-nate-Documents-GRACE-2/fd2df08a-a572-4b62-ba9a-e82d8a0a740e/scratchpad";
const browser = await chromium.launch();
const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });
page.on("console", (m) => console.log(`[${m.type()}]`, m.text().slice(0, 200)));
page.on("pageerror", (e) => console.log("[pageerror]", String(e).slice(0, 300)));
await page.goto("http://127.0.0.1:5173", { waitUntil: "domcontentloaded" });
await page.waitForTimeout(10000);
const bodyText = (await page.locator("body").innerText()).slice(0, 300);
console.log("BODY TEXT:", JSON.stringify(bodyText));
const rootChildren = await page.locator("#root > *").count();
console.log("root children:", rootChildren);
await page.screenshot({ path: `${OUT}/f1-diag.png` });
await browser.close();
